/**
 * Shared command resolver for the Manifest dispatcher.
 *
 * The URL path segment for [command] may be kebab-case (e.g. "soft-delete")
 * while Manifest command names are camelCase ("softDelete"). This module:
 *
 * 1. Loads the canonical merged command registry.
 * 2. Provides `resolveCommand(entity, commandSlug)` — tries exact match,
 *    then kebab-to-camel conversion.
 * 3. Returns the canonical camelCase command name (or null if unresolved).
 */

// Canonical merged registry — single source of truth for dispatcher + audit.
// Generated by scripts/manifest/compile.mjs → packages/manifest-ir/dist/commands.registry.json
import commandsRegistry from "@/../../packages/manifest-ir/dist/commands.registry.json";

// ---------------------------------------------------------------------------
// Registry types
// ---------------------------------------------------------------------------

interface RegistryEntry {
  entity: string;
  command: string;
  commandId: string;
}

// ---------------------------------------------------------------------------
// Kebab → camelCase conversion
// ---------------------------------------------------------------------------

/** Convert kebab-case to camelCase. e.g. "soft-delete" → "softDelete" */
function kebabToCamel(str: string): string {
  return str.replace(/-([a-z0-9])/g, (_: string, char: string) =>
    char.toUpperCase()
  );
}

// ---------------------------------------------------------------------------
// Registry build (lazily built — zero-cost if never called)
// ---------------------------------------------------------------------------

let _exactSet: Set<string> | undefined;
let _kebabToCamelMap: Map<string, string> | undefined;

function ensureRegistry(): void {
  if (_exactSet) return;

  const entries = commandsRegistry as RegistryEntry[];

  _exactSet = new Set<string>();
  _kebabToCamelMap = new Map<string, string>();

  for (const entry of entries) {
    const key = `${entry.entity}.${entry.command}`;
    _exactSet.add(key);

    const kebab = `${entry.entity}.${kebabToCamel(entry.command)}`;
    // If the kebab form differs from the camelCase form, register the mapping.
    // If they're the same (e.g. "create" → "create"), skip — exact match handles it.
    if (kebab !== key) {
      _kebabToCamelMap.set(kebab, entry.command);
    }
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export interface ResolvedCommand {
  /** The canonical camelCase command name from the manifest IR. */
  command: string;
  /** The registry entry for this command. */
  entry: RegistryEntry;
}

/**
 * Resolve a URL command slug to a canonical manifest command.
 *
 * Attempts exact match first (`entity.commandSlug`), then kebab→camel
 * conversion if the slug contains hyphens. Returns null if neither matches.
 */
export function resolveCommand(
  entity: string,
  commandSlug: string
): ResolvedCommand | null {
  ensureRegistry();

  const exactKey = `${entity}.${commandSlug}`;

  // 1. Exact match
  if (_exactSet!.has(exactKey)) {
    return {
      command: commandSlug,
      entry: { entity, command: commandSlug, commandId: exactKey },
    };
  }

  // 2. Kebab → camelCase fallback (only if slug contains hyphens)
  if (commandSlug.includes("-")) {
    const camelCommand = kebabToCamel(commandSlug);
    const camelKey = `${entity}.${camelCommand}`;
    if (_exactSet!.has(camelKey)) {
      return {
        command: camelCommand,
        entry: { entity, command: camelCommand, commandId: camelKey },
      };
    }
  }

  // 3. Reverse: maybe the URL uses camelCase but the map has a kebab entry?
  // (Shouldn't happen with manifest commands, but defensive.)
  const mappedCommand = _kebabToCamelMap!.get(exactKey);
  if (mappedCommand) {
    return {
      command: mappedCommand,
      entry: {
        entity,
        command: mappedCommand,
        commandId: `${entity}.${mappedCommand}`,
      },
    };
  }

  return null;
}

/**
 * Check if a (entity, command) pair exists in the registry.
 * Uses the same resolution logic as resolveCommand.
 */
export function isRegisteredCommand(
  entity: string,
  commandSlug: string
): boolean {
  return resolveCommand(entity, commandSlug) !== null;
}
